var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"1년 뒤.","JPN":"1年後。","ENG":"1 year later.","TWN":"1年後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"노르드나빅 남부. 셔우드 외성. \\n왕립 국경수비대 텃밭.","JPN":"ノルドナビックの南部。シャーウッド外郭。\\n王立国境守備隊の畑。","ENG":"Southern Nordnavik. Outer castle of Sherwood.\\nRoyal Border Guards' vegetable garden.","TWN":"諾爾德萊比南方 休烏特外城 \\n皇家國境護衛隊菜園"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"상태는 어떻지?","JPN":"状況はどうだ？","ENG":"How are things looking?","TWN":"狀態如何？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"평소보다 크네요. 이번에 만든 습도 조절기가 잘 듣나 봐요.","JPN":"いつもより大きいですね。今度作った湿度調節器がよく効いたみたいです。","ENG":"They're bigger than usual. I guess the humidifier we made seems to be working well.","TWN":"比平時還大呢，看來這次做的溼度調節器效果很不錯。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"수확 주기도 점점 빨라지겠군. 창고를 한 번 더 증축해야겠어.","JPN":"収穫サイクルもだんだん早まりそうだな。もう一度倉庫を増築しないといけない。","ENG":"Then our harvest cycle should also shorten. We'll need to expand the warehouse yet again.","TWN":"收成的週期也越來越短，需要再擴建倉庫。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"헤헤, 하지만 실컷 따 둬도 싹이 자라면 못 먹는 게 감자 아니겠어요?","JPN":"へへ、でもいっぱい収穫しておいても、ジャガイモって芽が生えると食べられないじゃないですか。","ENG":"Heh heh! Just hope the potatoes are still edible after they start sprouting.","TWN":"嘿嘿，可是就算全部收割起來，但馬鈴薯發芽的話就不能吃咧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"이런 좋은 날씨에 온종일 감자나 캐고 있어야 하다니…….","JPN":"こんないい天気に一日中ジャガイモを収穫しないといけないなんて……","ENG":"Can't believe I'm digging for potatoes on a fine day like this...","TWN":"天氣這麼好，我們竟然整天都在挖挖馬鈴薯……"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"그러게. 오늘 같은 날은 낚시하기 딱 좋은데 말이지.","JPN":"そうだなぁ。今日は釣り日和なんだけどなぁ。","ENG":"I feel ya. This weather's perfect for going fishing.","TWN":"就是說，今天的天氣超適合釣魚的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"이봐, 불만쟁이들. 소쿠리가 제일 가벼운 녀석은 오늘 나랑 같이 야간 정비다.","JPN":"おい、そこのクレーマーども。籠が一番軽いやつは今日俺一緒に徹夜整備だ。","ENG":"Hey, whiners. The person with the lightest basket today will join me tonight for night duty.","TWN":"喂，你們這些抱怨鬼，籃子最輕的人今天要和我一起加班維修機器喔！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"잘못 걸렸다간 흙이 아니라 기름칠을 실컷 하겠군.","JPN":"下手したら土じゃなくてオイルまみれになるな。","ENG":"Guess one of us will be digging all day and oiling machines all night.","TWN":"被逮到的話，身上沾到的可能不是泥巴而是機油。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"어이, 잠깐! 그 큰 감자는 내가 캔 거라고!","JPN":"おい、待てよ！　その大きいジャガイモは俺が掘ったやつだぞ！","ENG":"H-hey! That big tater's mine!","TWN":"喂，等一下！那顆大的馬鈴薯是我挖的！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_BORDER_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"수확 때마다 병사들과 함께 와 줘서 고맙습니다, 대장님.","JPN":"収穫する時にいつも兵士たちと来てくださってありがとうございます、隊長。","ENG":"Captain, thank you for always volunteering with your men to harvest crops.","TWN":"隊長，每次收成時你都和士兵們一起來幫忙，真是謝謝你。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"그런 의미로, 이번 수확의 절반은 가져가시죠.","JPN":"感謝の意味で、今回の収穫の半分はお持ち帰りください。","ENG":"Please, take half of today's yield as a token of my gratitude.","TWN":"這次的收成一半歸你吧，就當作是謝禮。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그렇게 많이 줘도 괜찮겠습니까?\xA0","JPN":"そんなにもらってもいいんですか？\xA0","ENG":"Are you sure it's okay to give us so much?\xA0","TWN":"給我這麼多沒關係嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"지휘관이 만들어 준 장치 덕분에 수확량이 크게 늘었습니다.","JPN":"指揮官が作ってくれた装置のおかげで、収穫量が大きく増えました。","ENG":"Our potato yields have never been better after Commander made that device.","TWN":"都是拜指揮官做的裝置所賜，收成才能增加這麼多。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"이제 식량을 아끼려다 누가 굶을 걱정도 많이 덜었죠.","JPN":"もう食糧を節約するために誰かが飢える心配をすることも減りました。","ENG":"Now we don’t have to worry about anyone starving.","TWN":"現在也不用因為要現在節省糧食，而擔心誰會挨餓。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"지휘관님에게는 고맙다고 이 늙은이 대신 전해 주세요.","JPN":"指揮官には感謝してると、この老人の代わりにお伝えください。","ENG":"Please, tell him that this old man appreciates his contribution.","TWN":"請代替我這個老頭子向指揮官說聲謝謝。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"알겠습니다. 간만에 시장에서 베이컨이라도 사 와야겠네요.","JPN":"わかりました。久しぶりに市場でベーコンでも買うことにします。","ENG":"Will do. I guess I should go to the market and buy some bacon.","TWN":"好的，那就久違地去市場買個培根吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GUARD_BORDER_NULL_A","text":{"KOREA":"살다 살다 여기서 카레를 먹어 보네.","JPN":"ここでカレーを食べられる日が来るなんてな。","ENG":"Who would've thought we'd ever eat curry in a place like this, right?","TWN":"真沒想有生之年竟然能在這裡吃到咖哩。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GUARD_BORDER_NULL_B","text":{"KOREA":"찐 감자도 괜찮지만 역시 엘라 대장님 요리가 제일이라니까.","JPN":"ふかしたジャガイモもいいけど、やっぱりエラ隊長の料理が一番だよな。","ENG":"Don't get me wrong, I like boiled potatoes. But Captain Ella's cooking really is the best!","TWN":"蒸馬鈴薯也不錯，果然艾拉隊長的手藝是最棒的。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"천천히 먹어. 많이 만들어 뒀으니까.","JPN":"ゆっくり食べて。たくさん作っておいたから。","ENG":"Slow down. There's enough for seconds and more.","TWN":"吃慢點，我有準備很多。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그런데 큐리안과 피터가 보이지 않는군.","JPN":"ところで、キュリアンとピーターが見えないな。","ENG":"But where is Curian and Peter?","TWN":"怎麼沒看到庫里安和彼得呢？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"지금쯤 헛간에 있을 겁니다. 이번 수확철에 감자 에일을 만들겠다고 벼르고 있었거든요.","JPN":"今頃小屋にいるはずです。今年の収穫時期にジャガイモのエールを作るって張り切ってましたから。","ENG":"They should be at the barn. I heard them talking about using some of the leftover potatoes to make spud ale.","TWN":"應該在倉庫裡，他們打算利用這次的收成釀造馬鈴薯啤酒。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"에일이라고?","JPN":"エールだって？","ENG":"Spud ale?","TWN":"啤酒？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"헤헤, 벌써부터 고소한 냄새가 나는 게 느낌이 좋은데요.","JPN":"へへ、もう香ばしい匂いがするというのは、幸先がいいですね。","ENG":"Heh heh...! It already smells so good.","TWN":"嘿嘿，已經有香氣咧，感覺不錯喔。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"<color=#ffd34c>단조로운 식사에 술을 더해 변화를 준다.</color> 확실히 좋은 아이디어야.","JPN":"<color=#ffd34c>単調な食事に酒を加えて変化させる。</color>確かにいいアイデアだ。","ENG":"<color=#ffd34c>Adding some alcohol to the boring and repetitive diet.</color> What a brilliant idea.","TWN":"<color=#ffd34c>在一成不變的飲食中加入酒來點變化，</color> 確實是個好主意。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이걸로 병사들의 사기를 고취시킨다면 더할 나위 없겠어.","JPN":"これで兵士の士気を高められるのなら言うことなしだ。","ENG":"All I wish for is for this to boost the morale of the soldiers.","TWN":"要是這能鼓舞士氣，那是再好不過的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"그야 당연하죠. 그 깐깐한 와트 씨도 술이라면 사족을 못 쓴다고요.","JPN":"そりゃもちろんですよ。あの気難しいワットさんも酒には目がないんです。","ENG":"Of course it will! Even Mr. Watt can't say no to alcohol!","TWN":"那是一定的，就連平時一板一眼的華特，只要提到酒就興奮得跟什麼一樣。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"감자를 쪄서 발효시키는 건가?","JPN":"ジャガイモをふかして発酵させているのか？","ENG":"Are you fermenting the potatoes after boiling them?","TWN":"馬鈴薯蒸熟後發酵的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"우왓! 어, 언제 오셨어요? 엘라 대장?","JPN":"うわっ！　い、いついらしたんですか？　エラ隊長。","ENG":"Whoa! W-when did you get here, Captain Ella?","TWN":"哇！艾拉隊長，你什麼時候來的？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"창고에서 연기가 새어 나오는데 그냥 지나칠 수가 있어야지.","JPN":"倉庫から煙があがってるのに通り過ぎるわけにもいかなくて。","ENG":"Seeing smoke coming from the barn, I came here thinking there was fire.","TWN":"我看到倉庫在冒煙，自然不可能袖手旁觀。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"자, 어떻게 된 일인지 설명해 봐.","JPN":"さて、どういうことなのか説明してもらおうか。","ENG":"Now, would you mind explaining what's going on here?","TWN":"來吧，麻煩解釋一下這是怎麼回事。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"아하하… 오해하지 마세요. 이건 엄연히 식량의 효율적인 소비로서…","JPN":"あはは……誤解しないでください。これはあくまで食糧の効率的な消費として……","ENG":"Ahaha... It's not what you think. This is but an efficient way of consuming surplus–","TWN":"哈哈哈……請不要誤會，我們在發揮糧食的價值…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"난 지휘관에게 묻는 거야, 피터.","JPN":"私は指揮官に聞いてるんだ、ピーター。","ENG":"I was asking the Commander, Peter.","TWN":"我是在問指揮官，彼得。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"으윽…….","JPN":"ううっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"남은 감자로 에일을 만드는 중이다. 이제 일주일만 발효시키면 완성이라는군.","JPN":"残ったジャガイモでエールを作ってるんだ。あと一週間ほど発酵させれば完成するらしい。","ENG":"We're making ale with the leftover potatoes. One more week of fermenting and it'll be finished.","TWN":"我們正在利用剩下的馬鈴薯釀造啤酒，接下來只要發酵一週便大功告成。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"병사들에게 삶은 감자를 대신해 특식으로 줄 계획이었어.","JPN":"兵士に茹でたジャガイモの代わりに、特別食として提供するつもりだったんだ。","ENG":"I plan on giving it to the soldiers as a treat instead of normal boiled potatoes as usual.","TWN":"想說可以給士兵當作蒸馬鈴薯之外的配餐。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"다음에도 이번처럼 작황이 좋을지는 장담 못 해.","JPN":"次も今回のように作柄がいいとは断言できない。","ENG":"Yes. However, we don't know if the next harvest will be as good as this one.","TWN":"我不敢保證下次的收成也能這麼好。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"기근이 들 수도 있고, 침식파에 노출돼서 텃밭 전체가 오염될 수도 있어.","JPN":"飢饉になるかもしれないし、侵食波に露出して畑全体が汚染されるかもしれない。","ENG":"There could be a famine, or the whole farmland could be contaminated by the Corruption ray.","TWN":"很有可能會發生饑荒，也可能因為暴露在侵蝕波之中導致整個菜園受到汙染。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"식량을 비축하려는 대장의 신중한 태도도 이해 못하는 건 아니야.","JPN":"食糧を貯えておこうとする隊長の慎重な態度も理解できないわけではない。","ENG":"I can understand your stance on how we should handle the food supply.","TWN":"我不是不明白你未雨綢繆的想法。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 혹시 <color=#ffd34c>여유를 가지지 않으면 평생 아무것도 즐길 수 없다</color>는 말, 들어 봤나?","JPN":"だが、<color=#ffd34c>余裕なくしては一生何も楽しめない</color>という言葉を聞いたことはあるか？","ENG":"However, have you ever heard of the phrase, <color=#ffd34c>\\"If you don't know how to relax, you'll never be able to enjoy anything in life\\"</color>?","TWN":"不過你有聽過這句話嗎？<color=#ffd34c>偶爾也要懂得放鬆，才能享受人生</color>。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"피터가 입에 달고 사는 말버릇이네.","JPN":"ピーターの口癖だね。","ENG":"Isn't that Peter's catchphrase?","TWN":"這不是彼得掛在嘴邊的口頭禪嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"하하…….","JPN":"はは……","ENG":"Ha ha...","TWN":"哈哈……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"대장 말대로 당장 내일 침식파에 시달리며 죽어가게 될지도 모르지.","JPN":"隊長の言うとおり、明日にでも侵食波に苦しみながら死んでいくかもしれない。","ENG":"We might get hit by the Corruption ray and wither away tomorrow, just like you say, Captain.","TWN":"就像你說的，很可能我們明天就會被侵蝕波給折磨死。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 그저 살아 있기만 할 뿐인 삶은 아무 의미도 없어.","JPN":"だが、ただ生きているというだけの人生は何の意味もないんだ。","ENG":"But what is life if you can't enjoy it?","TWN":"每天只是活著有什麼意義呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그리고 그건 이 창고에 쌓여 있는 감자들도 마찬가지다.","JPN":"それはこの倉庫に積まれているジャガイモも同じだ。","ENG":"The same thing can be said for all the potatoes stored in here.","TWN":"堆在倉庫裡的馬鈴薯也一樣，"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그들에게도 달콤한 술이 되어 모두를 즐겁게 할 수 있는 기회가……","JPN":"彼らにも甘い酒になり、みんなを楽しませる機会が……","ENG":"These potatoes have the opportunity to become delicious ale for everyone to enj─","TWN":"它們有機會成為甜甜的酒，讓大家開心……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"커헉…!","JPN":"ぐはっ……！","ENG":"Kuh...!","TWN":"咳咳…！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_STING_BIG"},{"id":"L20_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"지, 지휘관님!","JPN":"し、指揮官！","ENG":"S-Sir!","TWN":"指…指揮官！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"네가 하는 설명이 세 마디를 넘기면 그건 계획이 아니라 구차한 변명이란 뜻이야.","JPN":"あなたの説明が長くなるのは、計画じゃなくて見苦しい言いわけだからよ。","ENG":"It's not an explanation if it’s more than three sentences. That's an excuse.","TWN":"當你的解釋超過三句話，就表示這不是計劃，而是在狡辯。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"두 사람은 올해 동안 정기 순찰 고정 멤버다. 함부로 식량을 남용한 죄야.","JPN":"二人は今年の定期巡視の固定メンバーとする。勝手に食糧を乱用した罰だ。","ENG":"You two will be on patrol duty for the rest of this year. That's your punishment for wasting precious food.","TWN":"你們浪費糧食，就罰你們成為今年定時巡邏的班底。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"휴우…","JPN":"ふう……","ENG":"Whew...","TWN":"哀…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그리고.","JPN":"それから。","ENG":"And...","TWN":"還有。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"힉!","JPN":"ひっ！","ENG":"Eeek!","TWN":"唔！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"감자는 통째로 넣지 말고 썰어서 삶아. 삶은 뒤엔 으깨서 넣어야 발효가 돼.","JPN":"ジャガイモは丸ごと入れないで刻んでから茹でなさい。茹でた後は潰して入れないと発酵しないから。","ENG":"Don't boil the potatoes whole, you should slice them first. Then mash them up to make them ferment better.","TWN":"馬鈴薯不要放整塊，要切過再煮，煮完後要攪碎才能發酵。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"홉은 넣었어?","JPN":"ホップは入れたのか？","ENG":"Did you put in any hops?","TWN":"有放啤酒花嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"아뇨! 필요한 게 많다 보니 현실과 타협해서 홉은 넣지 않기로 했습니다!","JPN":"いいえ！　必要なものが多いので妥協してホップは入れないことにしました！","ENG":"N-no! We needed a lot of stuff so we compromised to not include any hops, ma'am!","TWN":"沒有！因爲需要很多種材料，最後決定跟現實妥協不放啤酒花！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그랬겠지. 시내로 가서 구해올 테니까 기다리고 있어.","JPN":"だろうね。街で買ってくるから待ってて。","ENG":"Figures. I'll go find some at the market. Wait until I get back.","TWN":"我就知道，我去城裡給你們弄來，等我。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"끄응……. 주먹이 더 매워졌군…….","JPN":"ぐぬぬ……げんこつがさらに痛烈になったな……","ENG":"Ugh... She keeps punching harder and harder...","TWN":"唔……拳頭變得更有力了……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"앗! 지휘관님, 괜찮아요?","JPN":"あっ！　指揮官、大丈夫ですか？","ENG":"S-sir! Are you okay?","TWN":"哎呀！指揮官，你沒事吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아니, 대장이 다녀올 동안 좀 쉬어야겠어…….","JPN":"いや、隊長が戻ってくるまで少し休む……","ENG":"I don't think so... I think I need to rest a bit while she goes to get us some hops.","TWN":"有事，隊長回來之前我要休息一下……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"헥…… 헤엑…… 대장님! 팔이, 팔이 빠질 것 같습니다!","JPN":"ひっ……はあ……隊長！腕、腕がもげそうです！","ENG":"*Huff...* *Huff...* C-Captain...! My arms feel like they're about to fall off!","TWN":"呼……呼…… 隊長！我的手臂…手臂要斷了啦！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"쉬지 말고 계속 저어.","JPN":"休んでないで混ぜ続けて。","ENG":"Keep stirring.","TWN":"不准停，繼續攪拌。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"엉터리로 만들어서 귀한 감자를 전부 버리게 되면, 그 때는 단순 징계로 안 끝날 거야.","JPN":"でたらめに作って大事なジャガイモを全部捨てることにでもなったら、その時には単なる罰ではすまないよ。","ENG":"If this fails and you waste our precious potatoes, you'll face more than simple disciplinary action.","TWN":"要是亂弄毀掉整鍋珍貴的馬鈴薯，到時候可有你好受的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다 함께 땀 흘려 일군 노동의 대가를 그냥 버릴 순 없지. 조금만 더 노력해라, 피터.","JPN":"共に汗水流して育てた労働の代価を捨てるわけにはいかない。もう少し頑張れ、ピーター。","ENG":"We can't just throw away all of our hard work and sweat. Push through the pain, Peter.","TWN":"當然不能浪費大家辛苦勞動的代價，彼得，再加點油。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신은 건더기나 제대로 걸러내도록 해, 지휘관.","JPN":"指揮官は固形物をしっかり取り除いて。","ENG":"Commander, you should also focus on getting all the clumps out.","TWN":"指揮官，你才要好好把渣渣撈掉啦！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래야지. 하지만 곧 식사 시간이…….","JPN":"そうだな。だがもうすぐ食事の時間が……","ENG":"Of course. But it's almost supper time, so...","TWN":"那當然，可是快要吃飯……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신들이 저지른 일을 마무리 짓기 전까지 저녁밥은 없어.","JPN":"やってしまったことに収拾をつけるまで夕飯はなしだから。","ENG":"There will be no food for you until you finish what you've begun.","TWN":"在你們好好收拾爛攤子之前，沒飯吃。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"놀고들 있네.","JPN":"ふざけてるな。","ENG":"What've we got here, huh?","TWN":"你們還真是開心呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_Q","text":{"KOREA":"군인이란 것들이 몰래 술이나 빚어? 당신들 대장이 대체 누구야?","JPN":"軍人たるものがこそこそと酒作りか？　隊長はいったい誰なんだ？","ENG":"Soldiers brewing alcohol? Who's your captain?","TWN":"身為軍人竟然私自釀酒？你們的隊長到底是誰？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"대장은 접니다만.","JPN":"隊長は私ですが。","ENG":"I'm their captain.","TWN":"我就是隊長。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_Q","text":{"KOREA":"하, 수비대장이란 자가 병사들을 이런 사적인 일에 부려먹는단 말이지?","JPN":"は、守備隊長が兵士をこんな私的なことにこき使ってるとはね？","ENG":"*Scoff* Using your power as Guard Captain to make soldiers do your personal bidding?","TWN":"哈，你身為護衛隊長，竟然使喚士兵私下替你做事？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_Q","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_Q","text":{"KOREA":"역시 근본이라곤 없는 시골뜨기들다워. 왕립이라는 수식어가 민망할 정도로군.","JPN":"やはり根本なんてない田舎者らしいな。王立という言葉が恥ずかしくなるくらいだ。","ENG":"Then again, what did I expect from a bunch of bumpkins. You should be ashamed to even call yourselves Royal Guards.","TWN":"果然是沒常識的鄉下土包子，簡直是愧對皇家這個稱謂。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_Q","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"못 보던 얼굴인데, 누구지?","JPN":"見ない顔だが、誰なんだ？","ENG":"She seems new around here. Who is she?","TWN":"我沒看過你，你是誰？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"어라? 저 군복은……?","JPN":"あれ？　あの軍服は……？","ENG":"Huh? That uniform...","TWN":"嗯？那身軍服是……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_Q","text":{"KOREA":"흥, 이 견장도 몰라 보는 병사가 있다니, 위부터 아래까지 참 덜떨어진 부대네.","JPN":"ふん、この肩章もわからない兵士がいるなんて、上から下までまったく程度の低い部隊だな。","ENG":"Hmph! A soldier who can't even recognize these epaulettes. This unit is a mess all around it seems?","TWN":"哼，竟然有人認不出來這個肩章，真是從上到下都沒什麼常識的部隊呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_Q","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"나는 국가 재건단의 수석 기술장교, 비비안 래시포드.","JPN":"私は国家再建団の首席技術将校、ビビアン・ラッシュフォード。","ENG":"I'm Vivian Rashford. Head technician officer of the National Reconstruction Alliance.","TWN":"我是國家重建委員會的首席技術軍官，薇薇安· 雷斯福特。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"사라진 <color=#ffd34c>열쇠</color>의 행방을 찾기 위해 수도에서 파견된 몸이다.","JPN":"消えた<color=#ffd34c>鍵</color>の行方を探すために首都から派遣された。","ENG":"I'm come from the capital searching for the whereabouts of the lost <color=#ffd34c>Key</color>.","TWN":"我是從首都派來要尋找<color=#ffd34c>鑰匙</color>的下落。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"초면에 실례했군요. 수도에서 소식을 받지 못해 대응이 소홀했습니다.","JPN":"初対面とはいえ失礼いたしました。首都からの連絡を受けておらず、対応が疎かになりました。","ENG":"Please excuse me and my men, but I haven't heard anything about a visitor from the capital.","TWN":"初次見面就這麼失禮，我沒收到首都的消息，以至於招待不周。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"차라리 잘 됐어. 그 첫인상이 당신들 민낯이라는 뜻이니까.","JPN":"むしろ好都合だ。初印象があなたたちの素顔だということだから。","ENG":"That's fine. It means your first impressions are who you really are.","TWN":"這樣反而更好，因為這就是你們最真實的樣子。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"서로 가식 떨 필요 없어서 다행이지 않아?","JPN":"お互い飾る必要がなくてよかったじゃないか。","ENG":"It's better this way, because then we don't have to pretend, no?","TWN":"這樣我們彼此也不需要裝腔作勢的，不覺得很好嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"면목 없습니다.","JPN":"面目ございません。","ENG":"Again, please accept my apologies.","TWN":"真是不好意思。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런데 저 병사는 왜 아직도 남아 있는 거야? 중요한 얘기라고 했을 텐데?","JPN":"ところで、あの兵士はどうしてまだ残ってるんだ？　重要は話だと言ったはずだが。","ENG":"Anyway, why is he still here? Didn't I say I had something important to talk about in private?","TWN":"那個士兵怎麼還在？我不是說有重要的事嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"저 사람은 저희 남부 국경수비대의 지휘참모입니다.","JPN":"あの者は我々南部国境守備隊の指揮参謀です。","ENG":"He is the Commanding Officer of the Southern Border Guards.","TWN":"這位是我們南方國境護衛隊的指揮官。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"하, 들을수록 어이가 없네. 부대를 도대체 어떤 식으로 운영하는 거람.","JPN":"は、聞けば聞くほど呆れかえる。一体どんな風に部隊を運営してるんだ？","ENG":"*Sigh...* You can't be serious. How on earth are you running this unit?","TWN":"哈，越聽越無言，你到底是怎麼管理部隊的？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"부대 운영 현황을 알고 싶으시다면 제가 대신……","JPN":"部隊の運営状況なら、私が代わりに……","ENG":"If you wish to know the current status of my unit, I will gladly explain─","TWN":"若你想知道部隊的情況，我可以代為…"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"됐어. 어차피 국경수비대란 곳들이야 하나 같이 주먹구구식이지.","JPN":"結構。どうせ国境守備隊なんてどこも大ざっぱだろう。","ENG":"Forget it. Border Guards are all the same, aren't they? They're all without any clear order.","TWN":"不用麻煩，反正國境護衛隊都差不多那樣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"왕립군이라고 거들먹거려도, 실상은 사지 멀쩡한 아무나 모아다 만든 오합지졸이니까.","JPN":"王立軍だと偉そうにしても、実は健康な人を適当に集めて作った烏合の衆なんだからな。","ENG":"Let's be honest. Even if they call themselves \\"Royal\\" guards, they're just a ragtag bunch of civilians.","TWN":"說是皇家軍隊好像很厲害，其實不過就是一群四肢發達的人湊在一起的烏合之衆。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"네놈들이 군인이라고 불리는 것만으로도 내가 몸담고 있는 군의 품위가 떨어져.","JPN":"貴様らが軍人と呼ばれているだけでも、私の所属してる軍の品格が落ちる。","ENG":"The mere fact you're called \\"soldiers\\" degrades the dignity of the military as a whole.","TWN":"你們這種傢伙也能被稱為是軍人，完全拉低軍人的格調。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그나마 여긴 카운터가 대장이라고 해서 조금 기대했는데…….","JPN":"それでもここはカウンターが隊長をしていると聞いて少し期待してたんだが……","ENG":"I had high hopes of this place when I heard a Counter was the captain...","TWN":"我聽說這裡的隊長是制裁者，原本還有點期待……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"외성 출신 아니랄까 봐 예상을 벗어나지 않네.","JPN":"外郭出身なだけあって、予想どおりだな。","ENG":"But just goes to show how predictable you outer castlers are.","TWN":"果然不出我所料，很符合外城的風格。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"실종된 성유물을 조사하러 왔다고 하셨죠. 도움이 필요하시다면 최대한 돕겠습니다.","JPN":"失踪した聖遺物を調査しに来られたとおっしゃいましたか。助けが必要でしたらできるだけ協力します。","ENG":"You said you came here to search for the lost Holy Relic, right? We'll do everything we can to aid you.","TWN":"你說你是來查失蹤的聖遺物對吧？有需要幫忙的話，我會盡力幫你的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"필요 없어. 조사는 당신들 도움 없이도 충분하니까.","JPN":"いらない。調査は助けがなくても十分できる。","ENG":"No need. I'll be fine without any of your help.","TWN":"不需要，完全不用你們幫忙，"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"나에겐 이미 훌륭한 조수 분이 계시거든.","JPN":"私にはすでに立派な助手がいるからな。","ENG":"You see, I already have an excellent assistant by my side.","TWN":"我自己有自備優秀的助手。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"네? 저, 저요?","JPN":"はい？　わ、私ですか？","ENG":"H-huh? M-me?","TWN":"嗯？我…是我嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"아…! 반갑습니다, 수비대 여러분!","JPN":"あ……！　はじめまして、守備隊のみなさん！","ENG":"Oh...! Pleased to meet you, Border Guards!","TWN":"喔…！護衛隊的大家，很高興認識你們！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L46_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"제프티 바이오테크의 연구원 한나 앤더스\xA0입니다. 편하게 한나라고 불러 주세요.","JPN":"ジェフティ・バイオテックの研究員、ハンナ・アンダーソンです。気軽にハンナと呼んでください。","ENG":"I'm Hanna Anderson, a researcher at Jehuty Biotech. But please, you can just call me Hanna.","TWN":"我是傑夫堤生物科技的研究員 漢娜·安德森。請叫我漢娜就好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"커다란 갑옷을 입고 계셔서 남성이신 줄 알았는데, 가녀린 목소리의 여성분이셨군요.","JPN":"大きな鎧を着ていらっしゃるので男性かと思いましたが、か弱い声の女性だったんですね。","ENG":"I was for sure you were a man wearing that bulky suit. But it turns out you're a woman with a soft voice.","TWN":"我看你穿著那身厚重的盔甲，還以為你是男生，結果是聲音溫柔的女生。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"아, 네. 저희 같은 학자는 침식지대를 돌아다니는 게 일상이라서요.","JPN":"あ、はい。私たちのような学者は毎日侵食地帯を歩き回ってますので。","ENG":"Oh, yes. This is normal for scholars because we go out into Corrupted Areas all the time.","TWN":"是的，因為像我們這樣的學者，必須經常出入侵蝕地帶。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L50_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"안전을 위해 강화복을 입고 다녀요. 블랙타이드 것이랑 다르게 일상에서도 쾌적하거든요.","JPN":"安全のために強化服を着てるんです。ブラックタイドのものとは違って、日常生活でも快適に過ごせるんですよ。","ENG":"We wear this power suit for safety. But unlike Black Tide's, this one is quite comfy to wear on a daily basis.","TWN":"安全起見，都會穿著強化服。不過不同於黑潮的，這個平時穿也蠻舒適的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"국가 재건단은 해외 기업의 연구 환경을 제공해 주는 대신 기술 지원을 받고 있어.","JPN":"国家再建団は海外企業に研究環境を提供する代わりに、技術を支援してもらってるんだ。","ENG":"The Alliance is getting technical support for helping an overseas company with their research.","TWN":"國家重建委員會會提供國外企業研究環境，同時接受技術支持。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"다시 말해, 너희들의 도움 따위가 필요해서 온 게 아니야.","JPN":"つまり、助けなんかが必要で来たわけじゃないということだ。","ENG":"In other words, we're not here because we need your help.","TWN":"我再說一次，我來不是因爲需要你們的幫助。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"괜히 실적 챙기려다 발목 잡지 말고, 근처에 얼씬거리는 침식체나 잘 처리해.","JPN":"実績欲しさに足を引っ張らないよう、周りをうろついている侵食体でもしっかり処理することだ。","ENG":"So don't slow us down by trying to look good. And keep this place clear of C.O.s, got it?","TWN":"不要因為想拚業績就拖累我，處理好在附近出現的侵蝕體就好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"늘 하던 일이니 그 정도는 할 수 있겠지?","JPN":"いつものことだから、そのくらいはできるだろう？","ENG":"It's what you've always done, so you can at least do that, right?","TWN":"這些事你們應該很熟悉吧？沒問題吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"물론입니다. 걱정마시길.","JPN":"もちろんです。ご心配には及びません。","ENG":"Of course. No need to worry, ma'am.","TWN":"當然，請放心。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그리고 우리가 언제라도 외성 밖으로 나갈 수 있도록 병사들에게 일러 둬.","JPN":"あと、私たちがいつでも外郭の外に出られるように兵士にも伝えておけ。","ENG":"Also, tell your soldiers that we are to be able to leave the outer castle at any time.","TWN":"然後告訴士兵們，我們可以隨意進出外城。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"조사는 언제부터 시작하실 예정이죠?","JPN":"調査はいつから開始する予定ですか？","ENG":"When are you planning to starting the investigation?","TWN":"請問你們預計什麼時候開始調查呢？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지금 당장.","JPN":"今すぐに。","ENG":"Right now.","TWN":"現在立刻。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"가시죠, 한나 씨.","JPN":"行きましょう、ハンナさん。","ENG":"Let's go, Miss Anderson.","TWN":"走吧，漢娜。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"네? 네에…!","JPN":"え？　はい……！","ENG":"Huh? O-okay...!","TWN":"蛤？喔…！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"미안하군. 내 실수로 대장이 오해 받게 됐어.","JPN":"すまないな。私がしくじって隊長が誤解された。","ENG":"Sorry for making you look bad because of my mistake.","TWN":"抱歉，都怪我不好，讓你被誤會。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"부하를 시켜서 술을 만들고 있던 정황은 사실이야. 오해라고 할 것도 없어.","JPN":"部下に命令して酒を作っていた状況は事実なんだ。誤解でもなんでもない。","ENG":"It's true that I made you brew alcohol. There was no misunderstanding there.","TWN":"使喚部下釀酒是事實，不算是誤會。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"으음. 재건단에서 오는 사람들은 전부 태도가 저런 식인가?","JPN":"ううむ。再建団から来る人はみんなあんな態度なのか？","ENG":"Hmm... Do all Alliance people have that kind of attitude?","TWN":"嗯嗯，重建委員會的人都是那副態度嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"국경수비대에 대한 평균 인식을 묻는 거라면, 맞아.","JPN":"国境守備隊への平均的な認識について聞いているのなら、そのとおりよ。","ENG":"If you're asking about how they perceive Border Guards, then yes.","TWN":"你是指對於國境護衛隊的認知嗎？沒錯。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"출신 무관하게 아무나 모아 만든 것도. 정규군에 비해 질서도 제대로 안 잡힌 오합지졸인 것도.","JPN":"出身を問わず適当に集めて作ったのも。正規軍に比べてしっかりとした秩序がない烏合の衆なのも。","ENG":"It's true anyone can become a Border Guard, and that we are a ragtag bunch of people with little to no order.","TWN":"一群人隨便湊在一起，和正規軍比起來沒什麼規矩可言的烏合之衆，"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래서 재건단 윗분들의 인정을 받지 못하고 있는 것도. 전부 사실이야.","JPN":"それで再建団の上層部に認められていないことも。全部事実。","ENG":"That's why the higher-ups at Alliance aren't willing to recognize us.","TWN":"沒受到重建委員會長官們的重視，這些全都是事實。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 저 장교는 한 가지 간과하고 있는 게 있어.","JPN":"だけど、あの将校が一つだけ見落としてることがある。","ENG":"But there's one thing she is overlooking.","TWN":"不過那個長官忘記一件事，"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"남부 외성 밖은 길잡이가 없으면 길 잃기 십상이란 걸 말이지.","JPN":"南部の外郭の外は案内人なしには迷いやすいってことをね。","ENG":"That it's easy to get lost out here without a proper guide.","TWN":"就是在南方外城外，若沒有人帶路，是很容易迷路的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};